VALUES
  ('social-worker-moex-05970', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關兒童及少年之身分權益的敘述，下列何者正確？', '["胎兒出生時為死產者，接生人不需要通報衛生主管機關備查", "直轄市、縣（市）主管機關應保存出養人、收養人及被收養兒童及少年之身分、健康等相關資訊之檔案", "法院認可兒童及少年之收養前，不得命收養人與兒童及少年先行共同生活一段時間", "胎兒出生後七日內，接生人應將其出生之相關資料通報衛生主管機關備查"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "8e1229169756", "answer_pdf_sha1": "32de1633409b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05971', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據兒童及少年福利與權益保障法規定，主管機關每幾年應辦理對兒童及少年身心發展等進行調查、統 計及分析？', '["二年", "三年", "四年", "五年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "8e1229169756", "answer_pdf_sha1": "32de1633409b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05972', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據家庭暴力防治法，有關預防及處遇之規定，下列敘述何者正確？', '["法院未核發民事保護令之前，警察人員不得在被害人住居所守護", "家庭暴力防治之執行人員，在執行職務時知有疑似家庭暴力情事者，應立即通報當地主管機關，至遲 不得逾四十八小時", "加害人處遇計畫之執行機關，不得將處遇情事告知被害人", "醫療機構對於家庭暴力之被害人，不得無故拒絶診療及開立驗傷診斷書"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "8e1229169756", "answer_pdf_sha1": "32de1633409b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05973', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據身心障礙者權益保障法之規定，所稱之身心障礙者，指下列各款身體系統構造或功能，有損傷或不 全導致顯著偏離或喪失，影響其活動與參與社會生活，經相關專業人員組織之專業團隊鑑定及評估，領 有身心障礙證明者，請問所稱各款有多少類別？', '["八類", "十二類", "十五類", "十六類"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "8e1229169756", "answer_pdf_sha1": "32de1633409b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05974', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關老人福利機構之設立規定，下列敘述何者錯誤？', '["老人福利機構之規模、面積、設施等事項標準，由中央主管機關會同中央目的事業主管機關定之", "經許可設立私立老人福利機構者，應於六個月內辦理財團法人登記", "公設民營機構不冠以公立或私立之名稱", "小型機構之設立且不對外募捐、不接受補助及不享受租稅減免者，得免辦財團法人登記"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "8e1229169756", "answer_pdf_sha1": "32de1633409b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05975', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據身心障礙者權益保障法，有關身心障礙者就業基金之規定，下列敘述何者錯誤？', '["由直轄市、縣（市）社政主管機關設置之", "其用途可用於核發超額進用身心障礙者之私立機構獎勵金", "其可作為辦理促進身心障礙者就業權益相關事項", "超額進用核發之獎勵金，金額最高按超額進用人數乘以每月基本工資二分之一計算"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "8e1229169756", "answer_pdf_sha1": "32de1633409b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05976', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關老人福利法內容之敘述，下列何者正確？', '["社會福利基金為老人福利經費來源之一", "主管機關應至少每四年辦理老人生活狀況調查", "主管老人就業免於歧視之主管機關為社政主管機關", "有關老人權益及福利事宜之代表中，老人代表不得少於四分之一"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "8e1229169756", "answer_pdf_sha1": "32de1633409b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05977', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '對於Esping-Andersen所著的《福利資本主義的三個世界》一書中的觀點，下列何者正確？', '["服務的供給是基於權利，且個人的生活不需依靠市場時，就是商品化", "福利國家希望修正不平等的結構，因此不會是一種階層化體系", "自由主義體制其目的是紓解貧窮與失業，其主要使用方法是社會保險", "社會民主體制運作原則是普及性福利，再分配方法與均一費率的給付結構"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "8e1229169756", "answer_pdf_sha1": "32de1633409b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05978', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關社會救助法的規定，下列敘述何者正確？', '["最低生活費係由中央、直轄市主管機關參照中央主計機關所公布當地區最近一年每人可支配所得平均 數百分之六十定之", "低收入戶於一定期間及額度內因就業而增加之收入，得免計入家庭總收入，最長以二年為限", "生活扶助現金給付所定金額，每四年調整一次", "中低收入戶之家庭成員就讀國內公立高級中等以上學校者，得申請減免學雜費，減免基準為百分之七十"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "8e1229169756", "answer_pdf_sha1": "32de1633409b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05979', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關勞工保險老年年金給付與國民年金保險老年年金給付的比較，下列敘述何者正確？', '["勞保老年年金給付年齡為60歲，民國109年調整至61歲；國保老年年金給付年齡為65歲", "勞保保險費率為7.5～15%；國保保險費率為6～12%", "勞保老年給付依保險年資合計每滿一年，按其平均月投保薪資之1.3%計算。國保老年給付依月投保金 額乘以其保險年資，再乘以1.55%所得之數額", "勞保被保險人投保金額依投保薪資分級表認定；國保被保險人投保金額採定額制"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "8e1229169756", "answer_pdf_sha1": "32de1633409b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
